import React from "react";
import { Container, Row, Col } from "reactstrap";
import { SectionXNeg, SectionYNeg, StaggeredText } from "./Animations";
import MediaQuery from "react-responsive";
import dem from "../images/demo.mp4"
 
function AboutMe () {
    return (
        <Container className="lg-container">
            <h2 className="headerdec mt-5 mb-5"><StaggeredText text={"About Me"}></StaggeredText></h2>
            <Row>
                <Col md={6}>
                    <div className="embed-responsive embed-responsive-16by9">
                        <video className="embed-responsive-item" controls style={{ borderRadius: '15px' }}>
                            <source src={dem} type="video/mp4" />
                            Your browser does not support the video tag.
                        </video>
                    </div>
                </Col>
                <Col md={4} xs={12} className="d-flex align-items-center headertext">
                    <MediaQuery maxWidth={1279}>
                        <SectionYNeg>
                            <div>
                            <p style={{fontFamily: "sans-serif"}}>I am here to make your digital imagination come to fruition.To be that guiding hand if your feeling stuck.</p>
                            </div>
                        </SectionYNeg>
                    </MediaQuery>
                    <MediaQuery minWidth={1280}>
                        <SectionXNeg>
                            <div>
                                <p style={{fontFamily: "sans-serif", fontSize: "18px"}}>I am here to make your digital imagination come to fruition.To be that guiding hand if your feeling stuck.</p>
                            </div>
                        </SectionXNeg>
                    </MediaQuery>
                </Col>
            </Row>
        </Container>
    )
}

export default AboutMe;