import React from 'react';
import { Container, Card, Row, Col } from 'react-bootstrap';
import { Swiper, SwiperSlide } from 'swiper/react';
import { StaggeredText } from './Animations';
import Fard from "../images/fardin.png"
import 'swiper/css';
import 'swiper/css/pagination';
import 'swiper/css/navigation';
import { Autoplay, Pagination, Navigation } from 'swiper/modules';

function TestiSlide() {
  return (
    <>
      <Container className="lg-container mb-4">
        <h2 className="headerdec mt-5" style={{ marginBottom: '40px', '@media screen and (min-width: 1280px)': { marginBottom: '0px' } }}><StaggeredText text={"Testimonial"}></StaggeredText></h2>
        <Row>
          <Col className="d-flex justify-content-center align-items-center">
            <div className='mb-4 mt-3'>
              <h5>Thoughts Shared...</h5>
            </div>
          </Col>
        </Row>
        <Row>
          <Col md={4}></Col>
          <Col md={4}>
            <Swiper
              spaceBetween={30}
              centeredSlides={true}
              autoplay={{
                delay: 2500,
                disableOnInteraction: false,
              }}
              pagination={{
                clickable: true,
              }}
              navigation={true}
              modules={[Autoplay, Pagination, Navigation]}
              className="mySwiper"
            >
              <SwiperSlide>
                  <Card style={{borderRadius: "20px", backgroundColor: "#353935"}}>
                      <Card.Body>
                          <div className='d-flex justify-content-center'>
                              <img src={Fard} style={{ width: '5rem', borderRadius: "120px"}}/>
                          </div>
                          <div className='d-flex justify-content-center mb-5' style={{color: "#F5F5F5"}}>
                              Fardin Rahman
                          </div>
                          <Card.Text style={{color: "#F5F5F5"}}>
                          "Some quick example text to build on the card title and make up the
                          bulk of the card's content".
                          </Card.Text>
                          <Card.Subtitle className='mt-2 text-muted'>5🌟</Card.Subtitle>
                      </Card.Body>
                  </Card>
              </SwiperSlide>
              <SwiperSlide>
                  <Card style={{borderRadius: "20px", backgroundColor: "#353935"}}>
                      <Card.Body>
                          <div className='d-flex justify-content-center'>
                              <img src={Fard} style={{ width: '5rem', borderRadius: "120px"}}/>
                          </div>
                          <div className='d-flex justify-content-center mb-5' style={{color: "#F5F5F5"}}>
                              Fardin Rahman
                          </div>
                          <Card.Text style={{color: "#F5F5F5"}}>
                          "Some quick example text to build on the card title and make up the
                          bulk of the card's content".
                          </Card.Text>
                          <Card.Subtitle className='mt-2 text-muted'>5🌟</Card.Subtitle>
                      </Card.Body>
                  </Card>
              </SwiperSlide>
            </Swiper>
          </Col>
          <Col md={4}></Col>
        </Row>
        <div className='d-flex justify-content-center' style={{marginTop: "60px"}}>
          <h3 style={{fontFamily: "montserrat"}}>I always give my heart and soul to deliver on my promise</h3>
        </div>
        <div className='d-flex justify-content-center' style={{fontFamily: "montserrat", marginBottom: "35px"}}><h4>Contact me if i may be of service ✌</h4></div>
      </Container>
    </>
  );
}

export default TestiSlide;